I made a poor man's polyfill that doesn't require importing any extra modules like babel. It just discards unicode flag in RegExps and erases parts of the patterns used in exceljs that require unicode support. 
It's pretty dirty but it allowed our app to work in IE and even exceljs seems to still do its job.

```ts
// Add this code to polyfills.ts

const { RegExp } = window;
try {
    new RegExp('a', 'u');
} catch (err) {
    // @ts-ignore
    window.RegExp =
        (pattern: string, flags: string | undefined) => {
            if (flags?.includes('u') === true) {
                // Ignore unicode flag in RegExp
                flags = flags === 'u' ? undefined : flags.replace('u', '');
                // Discard parts of the patterns used by exceljs that error out in non-unicode RegExps.
                pattern = pattern.replace(/\uDC00-\uDBFF/g, '');
                pattern = pattern.replace(/\uDC00-\uDB7F/g, '');

                return new RegExp(pattern, flags);
            }
            return new RegExp(pattern, flags);
        };
    // @ts-ignore
    window.RegExp.prototype = RegExp;
}

